package com.securebank.security;

import android.content.Context;
import android.content.pm.PackageManager;
import android.os.Build;
import android.provider.Settings;

import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

/**
 * Defense-in-depth device integrity checker that uses multiple signals
 * to assess device trustworthiness. No single check is relied upon alone.
 */
public class DeviceIntegrityChecker {

    public enum IntegrityLevel {
        TRUSTED,        // All checks pass
        DEGRADED,       // Some checks fail - limit functionality
        UNTRUSTED       // Critical checks fail - block sensitive operations
    }

    public static class IntegrityReport {
        private final IntegrityLevel level;
        private final List<String> failedChecks;
        private final int riskScore; // 0-100, higher = more risk

        public IntegrityReport(IntegrityLevel level, List<String> failedChecks, int riskScore) {
            this.level = level;
            this.failedChecks = failedChecks;
            this.riskScore = riskScore;
        }

        public IntegrityLevel getLevel() { return level; }
        public List<String> getFailedChecks() { return failedChecks; }
        public int getRiskScore() { return riskScore; }
    }

    private final Context context;

    public DeviceIntegrityChecker(Context context) {
        this.context = context.getApplicationContext();
    }

    /**
     * Performs comprehensive device integrity assessment using multiple independent checks.
     * This is NOT a single boolean flag - it aggregates multiple signals.
     */
    public IntegrityReport performFullIntegrityCheck() {
        List<String> failedChecks = new ArrayList<>();
        int riskScore = 0;

        // Check 1: Root detection via su binary presence
        if (checkForSuBinary()) {
            failedChecks.add("SU_BINARY_DETECTED");
            riskScore += 25;
        }

        // Check 2: Root detection via known root management apps
        if (checkForRootManagementApps()) {
            failedChecks.add("ROOT_MANAGEMENT_APP_DETECTED");
            riskScore += 20;
        }

        // Check 3: Check for dangerous system properties
        if (checkDangerousSystemProperties()) {
            failedChecks.add("DANGEROUS_SYSTEM_PROPERTIES");
            riskScore += 15;
        }

        // Check 4: Check for test-keys build
        if (checkForTestKeys()) {
            failedChecks.add("TEST_KEYS_BUILD");
            riskScore += 15;
        }

        // Check 5: Check for writable system partition
        if (checkForRWSystem()) {
            failedChecks.add("WRITABLE_SYSTEM_PARTITION");
            riskScore += 20;
        }

        // Check 6: Check for hooking frameworks (Xposed, Frida, etc.)
        if (checkForHookingFrameworks()) {
            failedChecks.add("HOOKING_FRAMEWORK_DETECTED");
            riskScore += 30;
        }

        // Check 7: Check if debugger is attached
        if (checkForDebugger()) {
            failedChecks.add("DEBUGGER_ATTACHED");
            riskScore += 25;
        }

        // Check 8: Check for emulator
        if (checkForEmulator()) {
            failedChecks.add("EMULATOR_DETECTED");
            riskScore += 20;
        }

        // Check 9: Verify app signature integrity (tamper detection)
        if (checkAppTampered()) {
            failedChecks.add("APP_SIGNATURE_TAMPERED");
            riskScore += 35;
        }

        // Check 10: Check developer options / USB debugging
        if (checkDeveloperOptions()) {
            failedChecks.add("DEVELOPER_OPTIONS_ENABLED");
            riskScore += 5;
        }

        // Determine integrity level based on aggregated risk score
        IntegrityLevel level;
        if (riskScore >= 50) {
            level = IntegrityLevel.UNTRUSTED;
        } else if (riskScore >= 20) {
            level = IntegrityLevel.DEGRADED;
        } else {
            level = IntegrityLevel.TRUSTED;
        }

        return new IntegrityReport(level, failedChecks, Math.min(riskScore, 100));
    }

    private boolean checkForSuBinary() {
        String[] paths = {
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su",
            "/su/bin/su"
        };

        for (String path : paths) {
            if (new File(path).exists()) {
                return true;
            }
        }

        // Also try executing su
        try {
            Process process = Runtime.getRuntime().exec(new String[]{"which", "su"});
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line = reader.readLine();
            reader.close();
            process.destroy();
            return line != null && !line.trim().isEmpty();
        } catch (Exception e) {
            // Expected on non-rooted devices
        }

        return false;
    }

    private boolean checkForRootManagementApps() {
        String[] rootPackages = {
            "com.topjohnwu.magisk",
            "eu.chainfire.supersu",
            "com.koushikdutta.superuser",
            "com.noshufou.android.su",
            "com.thirdparty.superuser",
            "com.yellowes.su",
            "com.zachspong.temprootremovejb",
            "com.ramdroid.appquarantine",
            "com.devadvance.rootcloak",
            "com.devadvance.rootcloakplus",
            "de.robv.android.xposed.installer",
            "com.saurik.substrate"
        };

        PackageManager pm = context.getPackageManager();
        for (String pkg : rootPackages) {
            try {
                pm.getPackageInfo(pkg, 0);
                return true;
            } catch (PackageManager.NameNotFoundException e) {
                // Expected - package not found
            }
        }
        return false;
    }

    private boolean checkDangerousSystemProperties() {
        try {
            String[] dangerousProps = {
                "ro.debuggable",
                "ro.secure"
            };

            Process process = Runtime.getRuntime().exec("getprop ro.debuggable");
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String value = reader.readLine();
            reader.close();
            process.destroy();

            if ("1".equals(value)) {
                return true;
            }

            process = Runtime.getRuntime().exec("getprop ro.secure");
            reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            value = reader.readLine();
            reader.close();
            process.destroy();

            if ("0".equals(value)) {
                return true;
            }
        } catch (Exception e) {
            // Ignore
        }
        return false;
    }

    private boolean checkForTestKeys() {
        String buildTags = Build.TAGS;
        return buildTags != null && buildTags.contains("test-keys");
    }

    private boolean checkForRWSystem() {
        try {
            Process process = Runtime.getRuntime().exec("mount");
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                if (line.contains("/system") && line.contains("rw")) {
                    reader.close();
                    process.destroy();
                    return true;
                }
            }
            reader.close();
            process.destroy();
        } catch (Exception e) {
            // Ignore
        }
        return false;
    }

    private boolean checkForHookingFrameworks() {
        // Check for Xposed
        try {
            Class.forName("de.robv.android.xposed.XposedBridge");
            return true;
        } catch (ClassNotFoundException e) {
            // Expected
        }

        // Check for Frida
        try {
            // Frida typically runs on a known port
            java.net.Socket socket = new java.net.Socket();
            socket.connect(new java.net.InetSocketAddress("127.0.0.1", 27042), 100);
            socket.close();
            return true;
        } catch (Exception e) {
            // Expected - Frida not running
        }

        // Check for Frida libraries in memory maps
        try {
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(new java.io.FileInputStream("/proc/self/maps")));
            String line;
            while ((line = reader.readLine()) != null) {
                if (line.contains("frida") || line.contains("gadget")) {
                    reader.close();
                    return true;
                }
            }
            reader.close();
        } catch (Exception e) {
            // Ignore
        }

        // Check for Substrate
        try {
            Class.forName("com.saurik.substrate.MS");
            return true;
        } catch (ClassNotFoundException e) {
            // Expected
        }

        return false;
    }

    private boolean checkForDebugger() {
        return android.os.Debug.isDebuggerConnected() || android.os.Debug.waitingForDebugger();
    }

    private boolean checkForEmulator() {
        return (Build.FINGERPRINT.startsWith("generic")
            || Build.FINGERPRINT.startsWith("unknown")
            || Build.MODEL.contains("google_sdk")
            || Build.MODEL.contains("Emulator")
            || Build.MODEL.contains("Android SDK built for x86")
            || Build.BOARD.equals("QC_Reference_Phone")
            || Build.MANUFACTURER.contains("Genymotion")
            || Build.HOST.startsWith("Build")
            || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
            || "google_sdk".equals(Build.PRODUCT)
            || Build.HARDWARE.contains("goldfish")
            || Build.HARDWARE.contains("ranchu"));
    }

    private boolean checkAppTampered() {
        try {
            // Verify the app's signing certificate hash
            // In production, compare against your known signing certificate hash
            android.content.pm.PackageInfo packageInfo = context.getPackageManager()
                .getPackageInfo(context.getPackageName(), PackageManager.GET_SIGNATURES);

            if (packageInfo.signatures == null || packageInfo.signatures.length == 0) {
                return true; // No signatures = tampered
            }

            // Calculate SHA-256 of the signing certificate
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            byte[] certHash = md.digest(packageInfo.signatures[0].toByteArray());
            String currentHash = bytesToHex(certHash);

            // Compare with expected hash (this should be your release signing certificate hash)
            // In production, this value should be obfuscated or stored securely
            String expectedHash = getExpectedSignatureHash();

            return !currentHash.equals(expectedHash);
        } catch (Exception e) {
            return true; // If we can't verify, assume tampered
        }
    }

    private boolean checkDeveloperOptions() {
        try {
            return Settings.Global.getInt(context.getContentResolver(),
                Settings.Global.ADB_ENABLED, 0) == 1;
        } catch (Exception e) {
            return false;
        }
    }

    private String getExpectedSignatureHash() {
        // In production, this should be your actual release signing certificate SHA-256 hash
        // This is a placeholder - replace with your actual certificate hash
        return "YOUR_RELEASE_CERTIFICATE_SHA256_HASH_HERE";
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}


