package com.securebank.security;

import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;

import java.security.KeyStore;
import java.util.UUID;

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;

/**
 * Manages user sessions with encryption and integrity-aware session policies.
 */
public class SecureSessionManager {

    private static final String KEYSTORE_ALIAS = "SecureBankSessionKey";
    private static final String PREFS_NAME = "secure_bank_session";
    private static final String KEY_SESSION_TOKEN = "encrypted_session_token";
    private static final String KEY_SESSION_EXPIRY = "session_expiry";
    private static final String KEY_SESSION_IV = "session_iv";
    private static final String KEY_INTEGRITY_LEVEL = "session_integrity_level";

    private static final long SESSION_DURATION_TRUSTED = 30 * 60 * 1000L;    // 30 minutes
    private static final long SESSION_DURATION_DEGRADED = 5 * 60 * 1000L;     // 5 minutes
    // UNTRUSTED devices should not have sessions for sensitive operations

    private final Context context;
    private final DeviceIntegrityChecker.IntegrityLevel integrityLevel;

    public SecureSessionManager(Context context, DeviceIntegrityChecker.IntegrityLevel integrityLevel) {
        this.context = context.getApplicationContext();
        this.integrityLevel = integrityLevel;
        initializeKeyStore();
    }

    private void initializeKeyStore() {
        try {
            KeyStore keyStore = KeyStore.getInstance("AndroidKeyStore");
            keyStore.load(null);

            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, "AndroidKeyStore");

                KeyGenParameterSpec.Builder builder = new KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256);

                // Require user authentication for trusted devices
                if (integrityLevel == DeviceIntegrityChecker.IntegrityLevel.TRUSTED) {
                    builder.setUserAuthenticationRequired(true)
                           .setUserAuthenticationValidityDurationSeconds(300);
                }

                keyGenerator.init(builder.build());
                keyGenerator.generateKey();
            }
        } catch (Exception e) {
            throw new SecurityException("Failed to initialize secure key store", e);
        }
    }

    public String createSession(String userId) {
        if (integrityLevel == DeviceIntegrityChecker.IntegrityLevel.UNTRUSTED) {
            throw new SecurityException("Cannot create session on untrusted device");
        }

        String sessionToken = UUID.randomUUID().toString() + "-" + System.currentTimeMillis();

        try {
            // Encrypt session token
            KeyStore keyStore = KeyStore.getInstance("AndroidKeyStore");
            keyStore.load(null);
            SecretKey key = (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);

            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            cipher.init(Cipher.ENCRYPT_MODE, key);

            byte[] iv = cipher.getIV();
            byte[] encryptedToken = cipher.doFinal(sessionToken.getBytes("UTF-8"));

            long sessionDuration = (integrityLevel == DeviceIntegrityChecker.IntegrityLevel.TRUSTED)
                ? SESSION_DURATION_TRUSTED : SESSION_DURATION_DEGRADED;

            SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            prefs.edit()
                .putString(KEY_SESSION_TOKEN, android.util.Base64.encodeToString(encryptedToken, android.util.Base64.NO_WRAP))
                .putString(KEY_SESSION_IV, android.util.Base64.encodeToString(iv, android.util.Base64.NO_WRAP))
                .putLong(KEY_SESSION_EXPIRY, System.currentTimeMillis() + sessionDuration)
                .putString(KEY_INTEGRITY_LEVEL, integrityLevel.name())
                .apply();

            return sessionToken;
        } catch (Exception e) {
            throw new SecurityException("Failed to create secure session", e);
        }
    }

    public boolean isSessionValid() {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        long expiry = prefs.getLong(KEY_SESSION_EXPIRY, 0);

        if (System.currentTimeMillis() > expiry) {
            clearSession();
            return false;
        }

        // Verify integrity level hasn't degraded since session creation
        String storedLevel = prefs.getString(KEY_INTEGRITY_LEVEL, "");
        if (!integrityLevel.name().equals(storedLevel)) {
            // Integrity level changed - invalidate session
            clearSession();
            return false;
        }

        return prefs.contains(KEY_SESSION_TOKEN);
    }

    public void clearSession() {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit().clear().apply();
    }
}


