package com.securebank.security;

import java.math.BigDecimal;

/**
 * Security gate that enforces transaction limits and requirements
 * based on device integrity level. This is a key defense-in-depth control.
 */
public class TransactionSecurityGate {

    public enum TransactionType {
        BALANCE_CHECK,
        INTERNAL_TRANSFER,
        EXTERNAL_TRANSFER,
        BILL_PAYMENT,
        WIRE_TRANSFER
    }

    public static class SecurityDecision {
        private final boolean allowed;
        private final boolean requiresAdditionalAuth;
        private final BigDecimal maxAmount;
        private final String reason;

        public SecurityDecision(boolean allowed, boolean requiresAdditionalAuth,
                                BigDecimal maxAmount, String reason) {
            this.allowed = allowed;
            this.requiresAdditionalAuth = requiresAdditionalAuth;
            this.maxAmount = maxAmount;
            this.reason = reason;
        }

        public boolean isAllowed() { return allowed; }
        public boolean requiresAdditionalAuth() { return requiresAdditionalAuth; }
        public BigDecimal getMaxAmount() { return maxAmount; }
        public String getReason() { return reason; }
    }

    private final DeviceIntegrityChecker.IntegrityReport integrityReport;

    public TransactionSecurityGate(DeviceIntegrityChecker.IntegrityReport integrityReport) {
        this.integrityReport = integrityReport;
    }

    /**
     * Evaluates whether a transaction should be allowed based on device integrity
     * and transaction characteristics.
     */
    public SecurityDecision evaluateTransaction(TransactionType type, BigDecimal amount) {
        DeviceIntegrityChecker.IntegrityLevel level = integrityReport.getLevel();

        switch (level) {
            case TRUSTED:
                return evaluateTrustedDevice(type, amount);
            case DEGRADED:
                return evaluateDegradedDevice(type, amount);
            case UNTRUSTED:
                return evaluateUntrustedDevice(type, amount);
            default:
                return new SecurityDecision(false, false, BigDecimal.ZERO,
                    "Unknown integrity level - transaction blocked for safety");
        }
    }

    private SecurityDecision evaluateTrustedDevice(TransactionType type, BigDecimal amount) {
        // Trusted devices get full functionality with standard limits
        switch (type) {
            case BALANCE_CHECK:
                return new SecurityDecision(true, false, null, "Allowed");
            case INTERNAL_TRANSFER:
                return new SecurityDecision(true, false, new BigDecimal("50000"), "Allowed");
            case EXTERNAL_TRANSFER:
                if (amount.compareTo(new BigDecimal("10000")) > 0) {
                    return new SecurityDecision(true, true, new BigDecimal("25000"),
                        "Additional authentication required for large external transfers");
                }
                return new SecurityDecision(true, false, new BigDecimal("25000"), "Allowed");
            case BILL_PAYMENT:
                return new SecurityDecision(true, false, new BigDecimal("10000"), "Allowed");
            case WIRE_TRANSFER:
                return new SecurityDecision(true, true, new BigDecimal("100000"),
                    "Wire transfers always require additional authentication");
            default:
                return new SecurityDecision(false, false, BigDecimal.ZERO, "Unknown transaction type");
        }
    }

    private SecurityDecision evaluateDegradedDevice(TransactionType type, BigDecimal amount) {
        // Degraded devices get reduced limits and always require additional auth for transfers
        switch (type) {
            case BALANCE_CHECK:
                return new SecurityDecision(true, false, null,
                    "Allowed with security advisory");
            case INTERNAL_TRANSFER:
                return new SecurityDecision(true, true, new BigDecimal("5000"),
                    "Reduced limit and additional auth required - device integrity degraded");
            case EXTERNAL_TRANSFER:
                return new SecurityDecision(true, true, new BigDecimal("1000"),
                    "Significantly reduced limit - device integrity degraded. " +
                    "Failed checks: " + String.join(", ", integrityReport.getFailedChecks()));
            case BILL_PAYMENT:
                return new SecurityDecision(true, true, new BigDecimal("2000"),
                    "Reduced limit and additional auth required");
            case WIRE_TRANSFER:
                return new SecurityDecision(false, false, BigDecimal.ZERO,
                    "Wire transfers are not available on devices with degraded integrity. " +
                    "Please use a trusted device or visit a branch.");
            default:
                return new SecurityDecision(false, false, BigDecimal.ZERO, "Unknown transaction type");
        }
    }

    private SecurityDecision evaluateUntrustedDevice(TransactionType type, BigDecimal amount) {
        // Untrusted devices can only view balance - all transactions blocked
        switch (type) {
            case BALANCE_CHECK:
                return new SecurityDecision(true, true, null,
                    "Balance check allowed with additional authentication. " +
                    "WARNING: This device has failed multiple integrity checks. " +
                    "Your financial data may be at risk. " +
                    "Failed checks: " + String.join(", ", integrityReport.getFailedChecks()));
            default:
                return new SecurityDecision(false, false, BigDecimal.ZERO,
                    "Transactions are blocked on this device due to security concerns. " +
                    "Device risk score: " + integrityReport.getRiskScore() + "/100. " +
                    "Failed checks: " + String.join(", ", integrityReport.getFailedChecks()) +
                    ". Please use a trusted device or visit a branch.");
        }
    }
}


