    private final String fromAccountId;
    private final String toAccountId;
    private final BigDecimal amount;
    private final String currency;
    private final String description;
    private final Date createdAt;
    private Status status;
    private String statusReason;
    private final String deviceIntegrityLevel;
    private final int deviceRiskScore;

    public Transaction(String fromAccountId, String toAccountId, BigDecimal amount,
                       String currency, String description,
                       String deviceIntegrityLevel, int deviceRiskScore) {
        this.transactionId = UUID.randomUUID().toString();
        this.fromAccountId = fromAccountId;
        this.toAccountId = toAccountId;
        this.amount = amount;
        this.currency = currency;
        this.description = description;
        this.createdAt = new Date();
        this.status = Status.PENDING;
        this.deviceIntegrityLevel = deviceIntegrityLevel;
        this.deviceRiskScore = deviceRiskScore;
    }

    public String getTransactionId() { return transactionId; }
    public String getFromAccountId() { return fromAccountId; }
    public String getToAccountId() { return toAccountId; }
