package com.securebank.transaction;

import android.content.Context;
import android.util.Log;

import com.securebank.model.Account;
import com.securebank.model.Transaction;
import com.securebank.security.DeviceIntegrityChecker;
import com.securebank.security.TransactionSecurityGate;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Processes financial transactions with integrated device integrity checks.
 * Implements defense-in-depth by checking device integrity at multiple points.
 */
public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";

    public interface TransactionCallback {
        void onTransactionApproved(Transaction transaction);
        void onTransactionRejected(Transaction transaction, String reason);
        void onAdditionalAuthRequired(Transaction transaction, String reason);
        void onTransactionCompleted(Transaction transaction);
        void onTransactionFailed(Transaction transaction, String error);
    }

    public interface AdditionalAuthProvider {
        void requestBiometricAuth(AuthCallback callback);
        void requestOtpVerification(AuthCallback callback);
    }

    public interface AuthCallback {
        void onAuthSuccess();
        void onAuthFailure(String reason);
    }

    private final Context context;
    private final DeviceIntegrityChecker integrityChecker;
    private final TransactionSecurityGate securityGate;
    private final DeviceIntegrityChecker.IntegrityReport currentIntegrityReport;
    private final ConcurrentHashMap<String, Transaction> pendingTransactions;
    private final List<Transaction> transactionHistory;
    private AdditionalAuthProvider authProvider;

    public TransactionProcessor(Context context) {
        this.context = context.getApplicationContext();
        this.integrityChecker = new DeviceIntegrityChecker(context);

        // Perform integrity check at initialization
        this.currentIntegrityReport = integrityChecker.performFullIntegrityCheck();
        this.securityGate = new TransactionSecurityGate(currentIntegrityReport);
        this.pendingTransactions = new ConcurrentHashMap<>();
        this.transactionHistory = new ArrayList<>();

        Log.i(TAG, "TransactionProcessor initialized. Device integrity: " +
            currentIntegrityReport.getLevel() +
            ", Risk score: " + currentIntegrityReport.getRiskScore());
    }

    public void setAdditionalAuthProvider(AdditionalAuthProvider provider) {
        this.authProvider = provider;
    }

    public DeviceIntegrityChecker.IntegrityReport getIntegrityReport() {
        return currentIntegrityReport;
    }

    /**
     * Initiates a transfer transaction with full security gate evaluation.
     */
    public void initiateTransfer(Account fromAccount, String toAccountId,
                                  BigDecimal amount, String description,
                                  TransactionSecurityGate.TransactionType type,
                                  TransactionCallback callback) {

        // Re-check integrity at transaction time (defense-in-depth)
        DeviceIntegrityChecker.IntegrityReport freshReport =
            integrityChecker.performFullIntegrityCheck();

        // If integrity degraded since initialization, use the worse assessment
        DeviceIntegrityChecker.IntegrityReport effectiveReport;
        if (freshReport.getRiskScore() > currentIntegrityReport.getRiskScore()) {
            Log.w(TAG, "Device integrity degraded since initialization! " +
                "Previous risk: " + currentIntegrityReport.getRiskScore() +
                ", Current risk: " + freshReport.getRiskScore());
            effectiveReport = freshReport;
        } else {
            effectiveReport = currentIntegrityReport;
        }

        // Create the security gate with the effective report
        TransactionSecurityGate effectiveGate = new TransactionSecurityGate(effectiveReport);

        // Evaluate the transaction through the security gate
        TransactionSecurityGate.SecurityDecision decision =
            effectiveGate.evaluateTransaction(type, amount);

        // Create transaction record with device integrity metadata
        Transaction transaction = new Transaction(
            fromAccount.getAccountId(),
            toAccountId,
            amount,
            fromAccount.getCurrency(),
            description,
            effectiveReport.getLevel().name(),
            effectiveReport.getRiskScore()
        );

        if (!decision.isAllowed()) {
            transaction.setStatus(Transaction.Status.REJECTED);
            transaction.setStatusReason(decision.getReason());
            transactionHistory.add(transaction);
            callback.onTransactionRejected(transaction, decision.getReason());
            return;
        }

        // Check amount limits
        if (decision.getMaxAmount() != null && amount.compareTo(decision.getMaxAmount()) > 0) {
            transaction.setStatus(Transaction.Status.REJECTED);
            String reason = "Amount exceeds maximum allowed (" + decision.getMaxAmount() +
                ") for current device integrity level: " + effectiveReport.getLevel();
            transaction.setStatusReason(reason);
            transactionHistory.add(transaction);
            callback.onTransactionRejected(transaction, reason);
            return;
        }

        // Check sufficient balance
        if (fromAccount.getBalance().compareTo(amount) < 0) {
            transaction.setStatus(Transaction.Status.REJECTED);
            transaction.setStatusReason("Insufficient funds");
            transactionHistory.add(transaction);
            callback.onTransactionRejected(transaction, "Insufficient funds");
            return;
        }

        // If additional auth is required, gate the transaction
        if (decision.requiresAdditionalAuth()) {
            pendingTransactions.put(transaction.getTransactionId(), transaction);

            if (authProvider != null) {
                callback.onAdditionalAuthRequired(transaction, decision.getReason());

                // Request biometric auth for degraded devices, OTP for trusted
                if (effectiveReport.getLevel() == DeviceIntegrityChecker.IntegrityLevel.DEGRADED) {
                    // On degraded devices, require both biometric AND OTP
                    authProvider.requestBiometricAuth(new AuthCallback() {
                        @Override
                        public void onAuthSuccess() {
                            authProvider.requestOtpVerification(new AuthCallback() {
                                @Override
                                public void onAuthSuccess() {
                                    completeTransaction(transaction, fromAccount, callback);
                                }

                                @Override
                                public void onAuthFailure(String reason) {
                                    rejectPendingTransaction(transaction,
                                        "OTP verification failed: " + reason, callback);
                                }
                            });
                        }

                        @Override
                        public void onAuthFailure(String reason) {
                            rejectPendingTransaction(transaction,
                                "Biometric auth failed: " + reason, callback);
                        }
                    });
                } else {
                    // Trusted devices just need biometric for high-value transactions
                    authProvider.requestBiometricAuth(new AuthCallback() {
                        @Override
                        public void onAuthSuccess() {
                            completeTransaction(transaction, fromAccount, callback);
                        }

                        @Override
                        public void onAuthFailure(String reason) {
                            rejectPendingTransaction(transaction,
                                "Authentication failed: " + reason, callback);
                        }
                    });
                }
            } else {
                rejectPendingTransaction(transaction,
                    "Additional authentication required but no auth provider configured",
                    callback);
            }
            return;
        }

        // Transaction approved without additional auth
        completeTransaction(transaction, fromAccount, callback);
    }

    private void completeTransaction(Transaction transaction, Account fromAccount,
                                      TransactionCallback callback) {
        try {
            transaction.setStatus(Transaction.Status.APPROVED);
            callback.onTransactionApproved(transaction);

            // Simulate server-side processing
            // In production, this would be an API call to the bank's backend
            processOnServer(transaction, fromAccount, callback);

        } catch (Exception e) {
            transaction.setStatus(Transaction.Status.FAILED);
            transaction.setStatusReason("Processing error: " + e.getMessage());
            transactionHistory.add(transaction);
            callback.onTransactionFailed(transaction, e.getMessage());
        } finally {
            pendingTransactions.remove(transaction.getTransactionId());
        }
    }

    private void processOnServer(Transaction transaction, Account fromAccount,
                                  TransactionCallback callback) {
        // In production, this would be a secure API call
        // The server should also validate the device integrity metadata
        // sent with the transaction for server-side risk assessment

        // Simulate successful processing
        BigDecimal newBalance = fromAccount.getBalance().subtract(transaction.getAmount());
        fromAccount.setBalance(newBalance);

        transaction.setStatus(Transaction.Status.COMPLETED);
        transactionHistory.add(transaction);
        callback.onTransactionCompleted(transaction);

        Log.i(TAG, "Transaction completed: " + transaction.getTransactionId() +
            " Amount: " + transaction.getAmount() +
            " Device integrity: " + transaction.getDeviceIntegrityLevel() +
            " Risk score: " + transaction.getDeviceRiskScore());
    }

    private void rejectPendingTransaction(Transaction transaction, String reason,
                                           TransactionCallback callback) {
        transaction.setStatus(Transaction.Status.REJECTED);
        transaction.setStatusReason(reason);
        pendingTransactions.remove(transaction.getTransactionId());
        transactionHistory.add(transaction);
        callback.onTransactionRejected(transaction, reason);
    }

    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory);
    }
}


// ============================================================
// AccountBalanceManager.java - Secure account balance display
// ============================================================
package com.securebank.account;

import android.content.Context;
import android.util.Log;

import com.securebank.model.Account;
import com.securebank.security.DeviceIntegrityChecker;
import com.securebank.security.TransactionSecurityGate;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.util.ArrayList;
import java.util.Currency;
import java.util.List;
import java.util.Locale;

/**
 * Manages account balance display with integrity-aware security controls.
 * Even balance viewing has protections on untrusted devices.
 */
public class AccountBalanceManager {

    private static final String TAG = "AccountBalanceManager";

    public interface BalanceCallback {
        void onBalanceRetrieved(List<AccountBalanceDisplay> balances);
        void onAdditionalAuthRequired(String reason);
        void onAccessDenied(String reason);
        void onError(String error);
    }

    public static class AccountBalanceDisplay {
        private final String accountId;
        private final String accountName;
        private final String accountType;
        private final String formattedBalance;
        private final boolean isMasked;
        private final String securityWarning;

        public AccountBalanceDisplay(String accountId, String accountName, String accountType,
                                      String formattedBalance, boolean isMasked,
                                      String securityWarning) {
            this.accountId = accountId;
            this.accountName = accountName;
            this.accountType = accountType;
            this.formattedBalance = formattedBalance;
            this.isMasked = isMasked;
            this.securityWarning = securityWarning;
        }

        public String getAccountId() { return accountId; }
        public String getAccountName() { return accountName; }
        public String getAccountType() { return accountType; }
        public String getFormattedBalance() { return formattedBalance; }
        public boolean isMasked() { return isMasked; }
        public String getSecurityWarning() { return securityWarning; }
    }

    private final Context context;
    private final DeviceIntegrityChecker integrityChecker;
    private final List<Account> accounts;

    public AccountBalanceManager(Context context) {
        this.context = context.getApplicationContext();
        this.integrityChecker = new DeviceIntegrityChecker(context);
        this.accounts = new ArrayList<>();
    }

    public void addAccount(Account account) {
        accounts.add(account);
    }

    /**
     * Retrieves account balances with integrity-aware display controls.
     */
    public void getAccountBalances(BalanceCallback callback) {
        DeviceIntegrityChecker.IntegrityReport report =
            integrityChecker.performFullIntegrityCheck();

        TransactionSecurityGate gate = new TransactionSecurityGate(report);
        TransactionSecurityGate.SecurityDecision decision =
            gate.evaluateTransaction(TransactionSecurityGate.TransactionType.BALANCE_CHECK, null);

        if (!decision.isAllowed()) {
            callback.onAccessDenied(decision.getReason());
            return;
        }

        if (decision.requiresAdditionalAuth()) {
            callback.onAdditionalAuthRequired(decision.getReason());
            return;
        }

        List<AccountBalanceDisplay> displays = new ArrayList<>();

        for (Account account : accounts) {
            AccountBalanceDisplay display = createBalanceDisplay(account, report);
            displays.add(display);
        }

        callback.onBalanceRetrieved(displays);
    }

    /**
     * Retrieves balances after additional authentication has been completed.
     */
    public void getAccountBalancesAfterAuth(BalanceCallback callback) {
        DeviceIntegrityChecker.IntegrityReport report =
            integrityChecker.performFullIntegrityCheck();

        List<AccountBalanceDisplay> displays = new ArrayList<>();

        for (Account account : accounts) {
            AccountBalanceDisplay display = createBalanceDisplay(account, report);
            displays.add(display);
        }

        callback.onBalanceRetrieved(displays);
    }

    private AccountBalanceDisplay createBalanceDisplay(
            Account account, DeviceIntegrityChecker.IntegrityReport report) {

        String formattedBalance;
        boolean isMasked;
        String securityWarning = null;

        switch (report.getLevel()) {
            case TRUSTED:
                formattedBalance = formatCurrency(account.getBalance(), account.getCurrency());
                isMasked = false;
                break;

            case DEGRADED:
                formattedBalance = formatCurrency(account.getBalance(), account.getCurrency());
                isMasked = false;
                securityWarning = "⚠️ Your device has potential security issues. " +
                    "Some features may be limited. " +
                    "Please ensure your device software is up to date.";
                break;

            case UNTRUSTED:
                // On untrusted devices, mask the full balance
                formattedBalance = maskBalance(account.getBalance(), account.getCurrency());
                isMasked = true;
                securityWarning = "🔒 Your device has failed security checks. " +
                    "Balance is partially hidden for your protection. " +
                    "Transactions are disabled on this device. " +
                    "Please use a trusted device or visit a branch for full access.";
                break;

            default:
                formattedBalance = "****";
                isMasked = true;
                securityWarning = "Unable to verify device security.";
        }

        return new AccountBalanceDisplay(
            account.getAccountId(),
            account.getAccountName(),
            account.getAccountType(),
            formattedBalance,
            isMasked,
            securityWarning
        );
    }

    private String formatCurrency(BigDecimal amount, String currencyCode) {
        try {
            NumberFormat format = NumberFormat.getCurrencyInstance(Locale.US);
            format.setCurrency(Currency.getInstance(currencyCode));
            return format.format(amount);
        } catch (Exception e) {
            return currencyCode + " " + amount.toPlainString();
        }
    }

    private String maskBalance(BigDecimal amount, String currencyCode) {
        // Show only the general magnitude, not the exact amount
        String formatted = formatCurrency(amount, currencyCode);
        if (formatted.length() > 4) {
            // Mask all but the first character and currency symbol
            StringBuilder masked = new StringBuilder();
            boolean pastCurrency = false;
            for (int i = 0; i < formatted.length(); i++) {
                char c = formatted.charAt(i);
                if (Character.isDigit(c)) {
                    if (!pastCurrency) {
                        pastCurrency = true;
                        masked.append(c);
                    } else {
                        masked.append('*');
                    }
                } else {
                    masked.append(c);
                }
            }
            return masked.toString();
        }
        return "****";
    }
}


// ============================================================
// SecurityAuditLogger.java - Logs security events for monitoring
// ============================================================
package com.securebank.security;

import android.content.Context;
import android.util.Log;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.Locale;

/**
 * Audit logger for security-relevant events. In production, these logs
 * should be sent to a server-side SIEM system for monitoring.
 */
public class SecurityAuditLogger {

    private static final String TAG = "SecurityAudit";

    public enum EventType {
        INTEGRITY_CHECK_PERFORMED,
        INTEGRITY_CHECK_FAILED,
        TRANSACTION_BLOCKED,
        TRANSACTION_LIMIT_REDUCED,
        ADDITIONAL_AUTH_REQUIRED,
        ADDITIONAL_AUTH_SUCCEEDED,
        ADDITIONAL_AUTH_FAILED,
        SESSION_CREATED,
        SESSION_INVALIDATED,
        BALANCE_MASKED,
        FEATURE_GATED
    }

    public static class AuditEvent {
        private final EventType type;
        private final String timestamp;
        private final String details;
        private final String integrityLevel;
        private final int riskScore;

        public AuditEvent(EventType type, String details,
                          String integrityLevel, int riskScore) {
            this.type = type;
            this.timestamp = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSZ",
                Locale.US).format(new Date());
            this.details = details;
            this.integrityLevel = integrityLevel;
            this.riskScore = riskScore;
        }

        public EventType getType() { return type; }
        public String getTimestamp() { return timestamp; }
        public String getDetails() { return details; }
        public String getIntegrityLevel() { return integrityLevel; }
        public int getRiskScore() { return riskScore; }

        @Override
        public String toString() {
            return String.format("[%s] %s - %s (Integrity: %s, Risk: %d)",
                timestamp, type, details, integrityLevel, riskScore);
        }
    }

    private static final List<AuditEvent> auditLog = new ArrayList<>();

    public static void logEvent(EventType type, String details,
                                 DeviceIntegrityChecker.IntegrityReport report) {
        AuditEvent event = new AuditEvent(
            type, details,
            report.getLevel().name(),
            report.getRiskScore()
        );

        auditLog.add(event);
        Log.i(TAG, event.toString());

        // In production: send to server-side logging/SIEM
        // sendToServer(event);
    }

    public static void logIntegrityCheckResult(DeviceIntegrityChecker.IntegrityReport report) {
        if (report.getFailedChecks().isEmpty()) {
            logEvent(EventType.INTEGRITY_CHECK_PERFORMED,
                "All integrity checks passed", report);
        } else {
            logEvent(EventType.INTEGRITY_CHECK_FAILED,
                "Failed checks: " + String.join(", ", report.getFailedChecks()),
                report);
        }
    }

    public static List<AuditEvent> getAuditLog() {
        return new ArrayList<>(auditLog);
    }
}


// ============================================================
// BankingActivity.java - Main activity demonstrating the integrated system
// ============================================================
package com.securebank.ui;

import android.app.Activity;
import android.app.AlertDialog;
import android.os.Bundle;
import android.util.Log;
import android.widget.Button;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;
import android.widget.Toast;

import com.securebank.account.AccountBalanceManager;
import com.securebank.model.Account;
import com.securebank.model.Transaction;
import com.securebank.security.DeviceIntegrityChecker;
import com.securebank.security.SecurityAuditLogger;
import com.securebank.security.TransactionSecurityGate;
import com.securebank.transaction.TransactionProcessor;

import java.math.BigDecimal;
import java.util.List;

/**
 * Main banking activity that demonstrates the complete security-gated
 * transaction flow with device integrity checks.
 */
public class BankingActivity extends Activity {

    private static final String TAG = "BankingActivity";

    private TransactionProcessor transactionProcessor;
    private AccountBalanceManager balanceManager;
    private DeviceIntegrityChecker.IntegrityReport integrityReport;

    private TextView tvIntegrityStatus;
    private TextView tvSecurityWarning;
    private LinearLayout accountsContainer;
    private Button btnTransfer;
    private Button btnViewBalance;
    private TextView tvTransactionLog;

    // Sample accounts for demonstration
    private Account checkingAccount;
    private Account savingsAccount;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Perform device integrity check immediately on launch
        DeviceIntegrityChecker integrityChecker = new DeviceIntegrityChecker(this);
        integrityReport = integrityChecker.performFullIntegrityCheck();

        // Log the integrity check result
        SecurityAuditLogger.logIntegrityCheckResult(integrityReport);

        // Initialize processors with integrity awareness
        transactionProcessor = new TransactionProcessor(this);
        balanceManager = new AccountBalanceManager(this);

        // Set up auth provider for additional authentication
        transactionProcessor.setAdditionalAuthProvider(new TransactionProcessor.AdditionalAuthProvider() {
            @Override
            public void requestBiometricAuth(TransactionProcessor.AuthCallback callback) {
                // In production, use BiometricPrompt API
                runOnUiThread(() -> {
                    new AlertDialog.Builder(BankingActivity.this)
                        .setTitle("Biometric Authentication Required")
                        .setMessage("Please authenticate with your fingerprint or face to proceed.")
                        .setPositiveButton("Simulate Success", (d, w) -> callback.onAuthSuccess())
                        .setNegativeButton("Cancel", (d, w) -> callback.onAuthFailure("User cancelled"))
                        .setCancelable(false)
                        .show();
                });
            }

            @Override
            public void requestOtpVerification(TransactionProcessor.AuthCallback callback) {
                // In production, send OTP via SMS/email and verify
                runOnUiThread(() -> {
                    new AlertDialog.Builder(BankingActivity.this)
                        .setTitle("OTP Verification Required")
                        .setMessage("An OTP has been sent to your registered phone. " +
                            "This additional step is required due to device security concerns.")
                        .setPositiveButton("Simulate Verify", (d, w) -> callback.onAuthSuccess())
                        .setNegativeButton("Cancel", (d, w) -> callback.onAuthFailure("OTP verification cancelled"))
                        .setCancelable(false)
                        .show();
                });
            }
        });

        // Create sample accounts
        checkingAccount = new Account("CHK-001", "Primary Checking", "CHECKING",
            new BigDecimal("15234.56"), "USD");
        savingsAccount = new Account("SAV-001", "High Yield Savings", "SAVINGS",
            new BigDecimal("52100.00"), "USD");

        balanceManager.addAccount(checkingAccount);
        balanceManager.addAccount(savingsAccount);

        setupUI();
        displayIntegrityStatus();
        loadBalances();
    }

    private void setupUI() {
        ScrollView scrollView = new ScrollView(this);
        LinearLayout mainLayout = new LinearLayout(this);
        mainLayout.setOrientation(LinearLayout.VERTICAL);
        mainLayout.setPadding(32, 32, 32, 32);

        // Title
        TextView tvTitle = new TextView(this);
        tvTitle.setText("SecureBank");
        tvTitle.setTextSize(24);
        mainLayout.addView(tvTitle);

        // Integrity status
        tvIntegrityStatus = new TextView(this);
        tvIntegrityStatus.setPadding(16, 16, 16, 16);
        tvIntegrityStatus.setTextSize(14);
        mainLayout.addView(tvIntegrityStatus);

        // Security warning
        tvSecurityWarning = new TextView(this);
        tvSecurityWarning.setPadding(16, 8, 16, 16);
        tvSecurityWarning.setTextSize(12);
        mainLayout.addView(tvSecurityWarning);

        // Accounts container
        accountsContainer = new LinearLayout(this);
        accountsContainer.setOrientation(LinearLayout.VERTICAL);
        accountsContainer.setPadding(0, 16, 0, 16);
        mainLayout.addView(accountsContainer);

        // View Balance button
        btnViewBalance = new Button(this);
        btnViewBalance.setText("Refresh Balances");
        btnViewBalance.setOnClickListener(v -> loadBalances());
        mainLayout.addView(btnViewBalance);

        // Transfer button
        btnTransfer = new Button(this);
        btnTransfer.setText("Transfer $500 (Checking → Savings)");
        btnTransfer.setOnClickListener(v -> initiateTransfer());
        mainLayout.addView(btnTransfer);

        // Large transfer button
        Button btnLargeTransfer = new Button(this);
        btnLargeTransfer.setText("Transfer $5,000 (External)");
        btnLargeTransfer.setOnClickListener(v -> initiateLargeExternalTransfer());
        mainLayout.addView(btnLargeTransfer);

        // Wire transfer button
        Button btnWireTransfer = new Button(this);
        btnWireTransfer.setText("Wire Transfer $25,000");
        btnWireTransfer.setOnClickListener(v -> initiateWireTransfer());
        mainLayout.addView(btnWireTransfer);

        // Transaction log
        TextView tvLogLabel = new TextView(this);
        tvLogLabel.setText("Transaction Log:");
        tvLogLabel.setTextSize(16);
        tvLogLabel.setPadding(0, 24, 0, 8);
        mainLayout.addView(tvLogLabel);

        tvTransactionLog = new TextView(this);
        tvTransactionLog.setTextSize(11);
        tvTransactionLog.setPadding(8, 8, 8, 8);
        mainLayout.addView(tvTransactionLog);

        scrollView.addView(mainLayout);
        setContentView(scrollView);
    }

    private void displayIntegrityStatus() {
        StringBuilder status = new StringBuilder();
        status.append("Device Integrity: ").append(integrityReport.getLevel());
        status.append("\nRisk Score: ").append(integrityReport.getRiskScore()).append("/100");

        if (!integrityReport.getFailedChecks().isEmpty()) {
            status.append("\nFailed Checks: ");
            status.append(String.join(", ", integrityReport.getFailedChecks()));
        }

        tvIntegrityStatus.setText(status.toString());

        switch (integrityReport.getLevel()) {
            case TRUSTED:
                tvIntegrityStatus.setBackgroundColor(0xFF4CAF50); // Green
                tvIntegrityStatus.setTextColor(0xFFFFFFFF);
                tvSecurityWarning.setText("");
                break;
            case DEGRADED:
                tvIntegrityStatus.setBackgroundColor(0xFFFF9800); // Orange
                tvIntegrityStatus.setTextColor(0xFFFFFFFF);
                tvSecurityWarning.setText("⚠️ Some device security checks failed. " +
                    "Transaction limits are reduced and additional authentication may be required.");
                tvSecurityWarning.setTextColor(0xFFFF6D00);
                break;
            case UNTRUSTED:
                tvIntegrityStatus.setBackgroundColor(0xFFF44336); // Red
                tvIntegrityStatus.setTextColor(0xFFFFFFFF);
                tvSecurityWarning.setText("🔒 SECURITY ALERT: This device has failed critical " +
                    "security checks. Transactions are disabled. Balance information is partially " +
                    "hidden. Please use a trusted device for full banking access.");
                tvSecurityWarning.setTextColor(0xFFD32F2F);
                btnTransfer.setEnabled(false);
                break;
        }
    }

    private void loadBalances() {
        accountsContainer.removeAllViews();

        balanceManager.getAccountBalances(new AccountBalanceManager.BalanceCallback() {
            @Override
            public void onBalanceRetrieved(List<AccountBalanceManager.AccountBalanceDisplay> balances) {
                runOnUiThread(() -> {
                    for (AccountBalanceManager.AccountBalanceDisplay balance : balances) {
                        TextView tv = new TextView(BankingActivity.this);
                        StringBuilder sb = new StringBuilder();
                        sb.append(balance.getAccountName())
                          .append(" (").append(balance.getAccountType()).append(")")
                          .append("\nBalance: ").append(balance.getFormattedBalance());

                        if (balance.isMasked()) {
                            sb.append(" [MASKED]");
                        }

                        if (balance.getSecurityWarning() != null) {
                            sb.append("\n").append(balance.getSecurityWarning());
                        }

                        tv.setText(sb.toString());
                        tv.setPadding(16, 12, 16, 12);
                        tv.setTextSize(13);
                        accountsContainer.addView(tv);
                    }
                });
            }

            @Override
            public void onAdditionalAuthRequired(String reason) {
                runOnUiThread(() -> {
                    new AlertDialog.Builder(BankingActivity.this)
                        .setTitle("Authentication Required")
                        .setMessage(reason + "\n\nPlease authenticate to view your balances.")
                        .setPositiveButton("Authenticate", (d, w) -> {
                            balanceManager.getAccountBalancesAfterAuth(this);
                        })
                        .setNegativeButton("Cancel", null)
                        .show();
                });
            }

            @Override
            public void onAccessDenied(String reason) {
                runOnUiThread(() -> {
                    Toast.makeText(BankingActivity.this,
                        "Access denied: " + reason, Toast.LENGTH_LONG).show();
                });
            }

            @Override
            public void onError(String error) {
                runOnUiThread(() -> {
                    Toast.makeText(BankingActivity.this,
                        "Error: " + error, Toast.LENGTH_LONG).show();
                });
            }
        });
    }

    private void initiateTransfer() {
        transactionProcessor.initiateTransfer(
            checkingAccount,
            savingsAccount.getAccountId(),
            new BigDecimal("500.00"),
            "Internal transfer",
            TransactionSecurityGate.TransactionType.INTERNAL_TRANSFER,
            createTransactionCallback("Internal Transfer $500")
        );
    }

    private void initiateLargeExternalTransfer() {
        transactionProcessor.initiateTransfer(
            checkingAccount,
            "EXT-ACCT-12345",
            new BigDecimal("5000.00"),
            "External payment",
            TransactionSecurityGate.TransactionType.EXTERNAL_TRANSFER,
            createTransactionCallback("External Transfer $5,000")
        );
    }

    private void initiateWireTransfer() {
        transactionProcessor.initiateTransfer(
            checkingAccount,
            "WIRE-INTL-67890",
            new BigDecimal("25000.00"),
            "International wire transfer",
            TransactionSecurityGate.TransactionType.WIRE_TRANSFER,
            createTransactionCallback("Wire Transfer $25,000")
        );
    }

    private TransactionProcessor.TransactionCallback createTransactionCallback(String label) {
        return new TransactionProcessor.TransactionCallback() {
            @Override
            public void onTransactionApproved(Transaction transaction) {
                runOnUiThread(() -> {
                    appendToLog(label + " - APPROVED (pending completion)");
                });
            }

            @Override
            public void onTransactionRejected(Transaction transaction, String reason) {
                runOnUiThread(() -> {
                    appendToLog(label + " - REJECTED: " + reason);
                    new AlertDialog.Builder(BankingActivity.this)
                        .setTitle("Transaction Rejected")
                        .setMessage(reason)
                        .setPositiveButton("OK", null)
                        .show();
                });

                SecurityAuditLogger.logEvent(
                    SecurityAuditLogger.EventType.TRANSACTION_BLOCKED,
                    label + " rejected: " + reason,
                    integrityReport
                );
            }

            @Override
            public void onAdditionalAuthRequired(Transaction transaction, String reason) {
                runOnUiThread(() -> {
                    appendToLog(label + " - Additional auth required: " + reason);
                });

                SecurityAuditLogger.logEvent(
                    SecurityAuditLogger.EventType.ADDITIONAL_AUTH_REQUIRED,
                    label + ": " + reason,
                    integrityReport
                );
            }

            @Override
            public void onTransactionCompleted(Transaction transaction) {
                runOnUiThread(() -> {
                    appendToLog(label + " - COMPLETED ✓ (ID: " +
                        transaction.getTransactionId().substring(0, 8) + "...)");
                    loadBalances(); // Refresh balances
                    Toast.makeText(BankingActivity.this,
                        "Transaction completed successfully!", Toast.LENGTH_SHORT).show();
                });
            }

            @Override
            public void onTransactionFailed(Transaction transaction, String error) {
                runOnUiThread(() -> {
                    appendToLog(label + " - FAILED: " + error);
                    Toast.makeText(BankingActivity.this,
                        "Transaction failed: " + error, Toast.LENGTH_LONG).show();
                });
            }
        };
    }

    private void appendToLog(String message) {
        String current = tvTransactionLog.getText().toString();
        String timestamp = new java.text.SimpleDateFormat("HH:mm:ss",
            java.util.Locale.US).format(new java.util.Date());
        tvTransactionLog.setText("[" + timestamp + "] " + message + "\n" + current);
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Re-check integrity when app comes to foreground
        DeviceIntegrityChecker checker = new DeviceIntegrityChecker(this);
        DeviceIntegrityChecker.IntegrityReport freshReport = checker.performFullIntegrityCheck();

        if (freshReport.getRiskScore() > integrityReport.getRiskScore()) {
            Log.w(TAG, "Device integrity degraded since last check!");
            integrityReport = freshReport;
            SecurityAuditLogger.logIntegrityCheckResult(integrityReport);
            displayIntegrityStatus();
            loadBalances();
        }
    }
}